// VALIDAR DISPONIBILIDAD + PROPONER HUECOS (Chihuahua)
// Videollamadas de 15 minutos para AgendaFlow

const gcalItems = (() => { try { return $('Google Calendar').all(); } catch(e) { return []; } })();
const eventos = gcalItems.map(item => ({
  start: item.json.start?.dateTime || item.json.start?.date || '',
  end: item.json.end?.dateTime || item.json.end?.date || '',
  summary: item.json.summary || ''
}));

const edit = $('Edit Fields').first().json;
const fechaConsultaRaw = edit.startDate || edit.start_date;
const endDateRaw = edit.endDate || edit.end_date;

if (!fechaConsultaRaw) throw new Error('Fecha de consulta no proporcionada.');

const OFFSET = '-06:00';
const SLOT_DURATION = 15 * 60 * 1000; // 15 minutos
const HALF_HR = 30 * 60 * 1000;
const MARGEN_MIN = 60 * 60 * 1000; // 1 hora de anticipación mínima
const AHORA = Date.now();
const LIMITE_MIN = AHORA + MARGEN_MIN;

const JORNADAS_POR_DIA = {
  0: [],
  1: [{ start: '09:00', end: '18:00' }],
  2: [{ start: '09:00', end: '18:00' }],
  3: [{ start: '09:00', end: '18:00' }],
  4: [{ start: '09:00', end: '18:00' }],
  5: [{ start: '09:00', end: '18:00' }],
  6: [{ start: '09:00', end: '14:00' }],
};

const isoToTS = iso => new Date(iso).getTime();

const tsToHora = ts => new Date(ts).toLocaleTimeString('es-MX', {
  hour: '2-digit', minute: '2-digit', hour12: true, timeZone: 'America/Chihuahua'
});

const tsToFechaHumana = ts => new Intl.DateTimeFormat('es-MX', {
  weekday: 'long', day: '2-digit', month: 'long', year: 'numeric',
  hour: '2-digit', minute: '2-digit', hour12: true,
  timeZone: 'America/Chihuahua'
}).format(new Date(ts));

const tsToDiaSemana = ts => new Intl.DateTimeFormat('es-MX', {
  weekday: 'long', timeZone: 'America/Chihuahua'
}).format(new Date(ts)).toLowerCase();

const tsToDiaNum = ts => {
  const parts = new Intl.DateTimeFormat('en-US', {
    weekday: 'short', timeZone: 'America/Chihuahua'
  }).formatToParts(new Date(ts));
  const dayMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  return dayMap[parts.find(p => p.type === 'weekday').value];
};

const diaBase = new Date(isoToTS(fechaConsultaRaw));
diaBase.setHours(0, 0, 0, 0);

function mismoDia(e) {
  const d = new Date(isoToTS(e.start));
  return d.getFullYear() === diaBase.getFullYear() &&
         d.getMonth() === diaBase.getMonth() &&
         d.getDate() === diaBase.getDate();
}

const ocupados = eventos.filter(mismoDia)
  .map(e => ({ s: isoToTS(e.start), e: isoToTS(e.end) }))
  .sort((a, b) => a.s - b.s);

for (let i = 1; i < ocupados.length; i++) {
  if (ocupados[i].s <= ocupados[i - 1].e) {
    ocupados[i - 1].e = Math.max(ocupados[i - 1].e, ocupados[i].e);
    ocupados.splice(i--, 1);
  }
}

function horaToTS(hhmm) {
  const [h, m] = hhmm.split(':').map(Number);
  const Y = diaBase.getFullYear(), M = `${diaBase.getMonth()+1}`.padStart(2,'0'), D = `${diaBase.getDate()}`.padStart(2,'0');
  return isoToTS(`${Y}-${M}-${D}T${`${h}`.padStart(2,'0')}:${`${m}`.padStart(2,'0')}:00${OFFSET}`);
}

const solicitadaTS = isoToTS(fechaConsultaRaw);
const diaNum = tsToDiaNum(solicitadaTS);
const JORNADAS = JORNADAS_POR_DIA[diaNum] || [];

if (JORNADAS.length === 0) {
  return [{
    fecha_consulta: fechaConsultaRaw,
    dia_semana: tsToDiaSemana(solicitadaTS),
    fecha_humana: tsToFechaHumana(solicitadaTS),
    disponible: false,
    motivo: 'No hay atención este día.',
    sugerencias: []
  }];
}

let preferenciaIniTS = null;
let preferenciaFinTS = null;
if (fechaConsultaRaw && endDateRaw) {
  const ini = isoToTS(fechaConsultaRaw);
  const fin = isoToTS(endDateRaw);
  const mismoDiaRango = String(fechaConsultaRaw).slice(0, 10) === String(endDateRaw).slice(0, 10);
  if (mismoDiaRango && fin > ini) {
    preferenciaIniTS = ini;
    preferenciaFinTS = fin - SLOT_DURATION;
  }
}

const libres = [];
for (const win of JORNADAS) {
  const winIni = horaToTS(win.start);
  const winFin = horaToTS(win.end) - SLOT_DURATION;
  for (let cursor = winIni; cursor <= winFin; cursor += HALF_HR) {
    const slotEnd = cursor + SLOT_DURATION;
    if (cursor < LIMITE_MIN) continue;
    const solapa = ocupados.some(b => cursor < b.e && slotEnd > b.s);
    if (!solapa) libres.push({ s: cursor, e: slotEnd });
  }
}

libres.sort((a, b) => a.s - b.s);
const libresFiltrados = (preferenciaIniTS !== null && preferenciaFinTS !== null)
  ? libres.filter(l => l.s >= preferenciaIniTS && l.s <= preferenciaFinTS)
  : libres;
const baseSugerencias = (libresFiltrados.length > 0) ? libresFiltrados : libres;
const sugerencias = baseSugerencias.slice(0, 5).map(l => ({
  inicio: tsToHora(l.s),
  fin: tsToHora(l.e)
}));

const muyCerca = solicitadaTS < LIMITE_MIN;
const choqueOcupado = ocupados.some(b => solicitadaTS < b.e && (solicitadaTS + SLOT_DURATION) > b.s);
const disponible = !muyCerca && !choqueOcupado;

return [{
  fecha_consulta: fechaConsultaRaw,
  dia_semana: tsToDiaSemana(solicitadaTS),
  fecha_humana: tsToFechaHumana(solicitadaTS),
  disponible,
  ...(muyCerca ? { motivo: 'El horario solicitado es muy próximo. Se requiere al menos 1 hora de anticipación.' } : {}),
  horarios_ocupados: eventos.filter(mismoDia).map(e => ({ inicio: e.start, fin: e.end })),
  sugerencias
}];
